SELECT
o.*,
s.short_name,
s.consignor,
schedule.actual_name scheduleName,
oe.enterprise_name
FROM
t_order o
LEFT JOIN t_shipper s ON s.shipper_id = o.shipper_id
LEFT JOIN t_employee schedule ON schedule.employee_id = o.schedule_id
LEFT JOIN t_oa_enterprise oe ON oe.enterprise_id = o.enterprise_id

    LEFT JOIN t_order_goods og on og.order_id = o.order_id


    o.deleted_flag = #{queryForm.deletedFlag}

    AND (INSTR(o.order_no,#{queryForm.keywords})
    or INSTR(o.create_user_name,#{queryForm.keywords})
    or INSTR(og.goods_name,#{queryForm.keywords})
    )


        AND INSTR(o.order_no,#{queryForm.orderNo})


        AND INSTR(o.shipper_contact,#{queryForm.shipperContact})


        AND INSTR(s.consignor,#{queryForm.consignor})


        AND INSTR(s.short_name,#{queryForm.shortName})


        AND o.split_transport_flag = #{queryForm.splitTransportFlag}


        AND INSTR(o.create_user_name,#{queryForm.createUserName})


        AND INSTR(o.container_location,#{queryForm.containerLocation})


        AND INSTR(o.placing_location,#{queryForm.placingLocation})


        AND INSTR(o.unloading_location,#{queryForm.unloadingLocation})


        AND INSTR(o.return_container_location,#{queryForm.returnContainerLocation})


        AND o.shipper_id = #{queryForm.shipperId}


        AND o.manager_id IN

            #{item}



        and DATE_FORMAT(o.latest_packing_time, '%Y-%m-%d') >= #{queryForm.latestPackingTimeStart}


        and DATE_FORMAT(o.latest_packing_time, '%Y-%m-%d') <= #{queryForm.latestPackingTimeEnd}


        and DATE_FORMAT(o.load_time, '%Y-%m-%d') >= #{queryForm.loadTimeStart}


        and DATE_FORMAT(o.load_time, '%Y-%m-%d') <= #{queryForm.loadTimeStart}


        and DATE_FORMAT(o.unload_time, '%Y-%m-%d') >= #{queryForm.unloadTimeStart}


        and DATE_FORMAT(o.unload_time, '%Y-%m-%d') <= #{queryForm.unloadTimeStart}


        AND o.business_type_code = #{queryForm.businessTypeCode}


        AND o.order_type = #{queryForm.orderType}


        AND og.goods_type = #{queryForm.cargoTypeClassificationCode}



        AND o.container_business_type_id = #{queryForm.containerBusinessTypeId}



        AND o.status = #{queryForm.status}



        AND o.area_id = #{queryForm.areaId}



        AND o.cabinet_id = #{queryForm.cabinetId}



        AND o.schedule_id = #{queryForm.scheduleId}



        AND o.schedule_flag = #{queryForm.scheduleFlag}



        AND o.enterprise_id = #{queryForm.enterpriseId}



        and DATE_FORMAT(o.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(o.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        and o.status != #{queryForm.excludeOrderStatus}



    GROUP BY o.order_id


    ORDER BY o.create_time DESC

select  * from t_order where deleted_flag = #{deletedFlag}
AND order_id in

    #{item}

SELECT shipper_id, DATE_FORMAT( create_time, '%Y-%m' ) month, COUNT( 1 ) count FROM t_order WHERE status != #{queryForm.excludeStatus} AND DATE_FORMAT( create_time, '%Y' ) = #{queryForm.year} AND enterprise_id = #{queryForm.enterpriseId}
AND shipper_id IN
#{item}
GROUP BY shipper_id, DATE_FORMAT( create_time, '%Y-%m' )

SELECT
DATE_FORMAT( create_time, '%Y-%m' ) month,
COUNT( 1 ) count
FROM
t_order
where status != #{queryForm.excludeStatus} and deleted_flag = #{queryForm.deletedFlag}
AND DATE_FORMAT( create_time, '%Y' ) = #{queryForm.year}
AND enterprise_id = #{queryForm.enterpriseId}

    AND shipper_id in

        #{item}


GROUP BY
DATE_FORMAT( create_time, '%Y-%m' )

select o.shipper_id, s.consignor, s.short_name, s.disable_flag from t_order o left join t_shipper s on o.shipper_id = s.shipper_id where o.status != #{queryForm.excludeStatus} and o.deleted_flag = #{queryForm.deletedFlag}
AND ( INSTR(s.consignor,#{queryForm.keywords}) or INSTR(s.short_name,#{queryForm.keywords}) )
AND o.enterprise_id = #{queryForm.enterpriseId}
group by o.shipper_id

