        AND enterprise_id = #{queryForm.enterpriseId}


        AND DATE_FORMAT(create_time, '%Y-%m-%d') >= #{queryForm.startDate}


        AND DATE_FORMAT(create_time, '%Y-%m-%d') <= #{queryForm.endDate}


        AND create_user_id IN

            #{item}

SELECT order_id,
       schedule_id
FROM t_order
WHERE schedule_flag = #{queryForm.scheduleFlag}
  and status != #{queryForm.excludeOrderStatus}

    AND enterprise_id = #{queryForm.enterpriseId}


    AND DATE_FORMAT(create_time, '%Y-%m-%d') >= #{queryForm.startDate}


    AND DATE_FORMAT(create_time, '%Y-%m-%d') <= #{queryForm.endDate}


